新建 src/coach/audit_health.py：
```python """S8.1 审计分级门禁 — gate 6 (audit_gate) 运行时实现。
只读审计评分器——聚合已有 P0/P1 finding，计算审计健康评分。 不修改审计流程，不熔断，不降级。 """ from dataclasses import dataclass, field from datetime import datetime, timezone from typing import Any
@dataclass class AuditFinding: """单条审计发现。""" severity: str # "P0" | "P1" | "P2" | "P3" category: str # "security" | "quality" | "coverage" | "drift" | "contract" detail: str source: str = "" # 审计来源（S10/S20/S30/...） timestamp: str = ""
def is_blocking(self) -> bool: return self.severity == "P0"
def is_warning(self) -> bool: return self.severity == "P1"
@dataclass class AuditHealthScore: """审计健康评分。""" score: float # 0.0 (最差) - 1.0 (最佳) p0_count: int p1_count: int p0_blocking: bool # P0 > 0 → blocking p1_above_threshold: bool # P1 > threshold → warning p1_threshold: int detail: str = ""
def to_dict(self) -> dict: return { "score": self.score, "p0_count": self.p0_count, "p1_count": self.p1_count, "p0_blocking": self.p0_blocking, "p1_above_threshold": self.p1_above_threshold, "p1_threshold": self.p1_threshold, "detail": self.detail, }
def audit_health(self) -> dict: """返回 gate 6 (audit_gate) 所需的 audit_health 指标。""" return { "audit_health_score": self.score, "p0_count": self.p0_count, "p1_count": self.p1_count, "p0_blocking": self.p0_blocking, "gate_pass": not self.p0_blocking and not self.p1_above_threshold, }
class AuditHealthScorer: """审计健康评分器——聚合 finding 并计算评分。
评分规则： - P0=0 且 P1=0 → score=1.0 (完美) - P0=0 且 P1≤threshold → score=0.8+ (良好) - P0=0 且 P1>threshold → score=0.5+ (告警) - P0>0 → score<0.5 (阻断) """
def __init__(self, p1_threshold: int = 3, history_window: int = 10): self.p1_threshold = p1_threshold self.history_window = history_window self._history: list[AuditHealthScore] = []
def evaluate(self, findings: list[AuditFinding]) -> AuditHealthScore: p0_count = sum(1 for f in findings if f.is_blocking()) p1_count = sum(1 for f in findings if f.is_warning())
p0_blocking = p0_count > 0 p1_above = p1_count > self.p1_threshold
if p0_blocking: # P0 阻断：score = 0.1 + 衰减 base = max(0.0, 0.3 - p0_count * 0.1) elif p1_above: # P1 超标：score = 0.5~0.7 excess = p1_count - self.p1_threshold base = max(0.3, 0.7 - excess * 0.05) else: # 健康：score = 0.8~1.0 base = 0.9 + (self.p1_threshold - p1_count) * 0.03 base = min(1.0, base)
score = round(base, 4) result = AuditHealthScore( score=score, p0_count=p0_count, p1_count=p1_count, p0_blocking=p0_blocking, p1_above_threshold=p1_above, p1_threshold=self.p1_threshold, detail=self._compose_detail(p0_count, p1_count, p0_blocking, p1_above), )
self._history.append(result) if len(self._history) > self.history_window: self._history.pop(0) return result
def trend(self) -> dict: """返回历史评分趋势。""" if not self._history: return {"scores": [], "trend": "stable", "average": 1.0} scores = [h.score for h in self._history] avg = sum(scores) / len(scores) if len(scores) >= 3: first_half = sum(scores[:len(scores)//2]) / (len(scores)//2) second_half = sum(scores[len(scores)//2:]) / (len(scores) - len(scores)//2) if second_half - first_half > 0.05: trend = "improving" elif first_half - second_half > 0.05: trend = "declining" else: trend = "stable" else: trend = "stable" return { "scores": [round(s, 4) for s in scores], "trend": trend, "average": round(avg, 4), "window": len(scores), }
@staticmethod def _compose_detail(p0: int, p1: int, p0_block: bool, p1_above: bool) -> str: parts = [] if p0 > 0: parts.append(f"P0={p0}(阻断)") if p1 > 0: parts.append(f"P1={p1}") if p0_block: parts.append("门禁阻断") elif p1_above: parts.append("P1 超阈值告警") else: parts.append("健康") return " | ".join(parts) if parts else "无 finding, 健康"
```
关键设计决策： - P0 > 0 直接阻断 gate（score < 0.5） - P1 超过阈值触发告警但不阻断（0.5 ≤ score < 0.7） - P0=0, P1=0 → score=1.0 (完美) - 历史滑动窗口追踪趋势（improving/declining/stable）
